UPDATE public.ai_prompt_settings
SET prompt_text = prompt_text || E'\n\n=== ФОРМАТ ОПИСАНИЯ БИОМАРКЕРА ===\n' ||
'- Сразу после якоря <!-- anchor:biomarker КОД --> НЕ дублируй имя биомаркера и его код в первой строке. Имя и код («Гемоглобин (Hb)») выводятся карточкой автоматически на стороне клиента.\n' ||
'- Описание начинай ПРЯМО с прозы. Допустимо начать предложение с имени биомаркера, ТОЛЬКО если это часть осмысленного предложения с подлежащим, например: «Эритроциты, или красные кровяные клетки, играют ключевую роль…».\n' ||
'- ЗАПРЕЩЕНО: «Гемоглобин (Hb)\nГемоглобин — это белок…» (двойной заголовок) и «Гемоглобин — это белок, который…» (имя + тире/двоеточие как заголовок) — обе формы создают дубликат на экране.\n' ||
'- Если хочешь начать с определения, пиши без имени: «Это белок в красных кровяных клетках, который переносит кислород…» или «Белок, который переносит кислород…».',
    updated_at = now()
WHERE key = 'global_biomarkers_instructions';